'use client'

import { CMSLink } from '@/components/Link'
import { Cart } from '@/components/Cart'
import { OpenCartButton } from '@/components/Cart/OpenCart'
import { Search } from '@/components/Search'
import Link from 'next/link'
import React, { Suspense } from 'react'

import { MobileMenu } from './MobileMenu'
import type { Header } from 'src/payload-types'

import { LogoIcon, CasaBrandLogo } from '@/components/icons/logo'
import { usePathname } from 'next/navigation'
import { cn } from '@/utilities/cn'
import clsx from 'clsx'
import { useMediaQuery } from '@/hooks/use-media-query'
import { ConfectionLeafs } from '../icons/confections'

type Props = {
  header: Header
}

export function HeaderClient({ header }: Props) {
  const menu = header.navItems || []
  const pathname = usePathname()
  const isMobile = useMediaQuery('(max-width: 768px)')

  return (
    <header className="relative z-20 border-b">
      <ConfectionLeafs className="w-50 h-auto absolute -top-5 xs:left-6 md:right-6" />
      <ConfectionLeafs className="hidden md:block w-64 h-auto absolute bottom-6 left-6" />
      <nav className="container z-50">
        <div className="flex items-center justify-between py-3 md:py-4">
          {/*<div className="flex items-center md:hidden">
            <Suspense fallback={null}>
              <MobileMenu menu={menu} />
            </Suspense>
          </div>*/}

          <Link className="flex items-center z-50" href="/">
            <CasaBrandLogo className="w-12 h-auto" />
          </Link>

          <div className="hidden md:flex flex-1 justify-center px-8">
            {header.showSearch && (
              <div className="w-full max-w-md">
                <Suspense fallback={null}>
                  <Search />
                </Suspense>
              </div>
            )}
          </div>

          <div className="flex items-center gap-4">
            {header.showCart && (
              <Suspense fallback={<OpenCartButton />}>
                <Cart />
              </Suspense>
            )}
          </div>
        </div>
        <div className="md:hidden flex items-center justify-between py-3 md:py-4">
          <Suspense fallback={null}>
            <Search />
          </Suspense>
        </div>

        {menu.length ? (
          <div className="md:block">
            <ul className="flex items-center justify-center gap-12 py-3">
              {menu
                .filter((item) => (isMobile ? item.link.label.toLowerCase() !== `catering` : true))
                .map((item) => (
                  <li key={item.id} className="md:mx-12">
                    <CMSLink
                      {...item.link}
                      size={'clear'}
                      className={cn(
                        'relative text-sm capitalize font-semibold font-sans h-auto w-auto text-center',
                        {
                          'border-b border-secondary':
                            item.link.url && item.link.url !== '/'
                              ? pathname.includes(item.link.url)
                              : false,
                        },
                      )}
                      appearance="nav"
                    >
                      {getMenuIcon(item.link.label.toLowerCase(), 'w-8 md:w-10 h-auto')}
                      {/*<FoodHubIcon className= />*/}
                    </CMSLink>
                  </li>
                ))}
            </ul>
          </div>
        ) : null}
      </nav>
    </header>
  )
}

const getMenuIcon = (label: string, className: string) => {
  switch (label) {
    case 'bulk orders':
      return <BulkOrderIcon className={className} />
    case 'restaurant':
      return <RestaurantIcon className={className} />
    case 'food hub':
      return <FoodHubIcon className={className} />
    case 'catering':
      return <CateringIcon className={className} />
    default:
      return <FoodHubIcon className={className} />
  }
}

